// NOTE: All test dates use UTC noon (T12:00:00Z) intentionally.
// This keeps dates unambiguous across timezones during testing.
// In production, always use dateHelpers.toLocalDayKey() for dayKey values.

jest.mock("../../config/firebase", () => ({
  db: null,
}));

jest.mock("firebase/firestore", () => ({
  Timestamp: { fromDate: jest.fn((value) => value) },
  addDoc: jest.fn(),
  collection: jest.fn(),
  doc: jest.fn(),
  getDocs: jest.fn(),
  query: jest.fn(),
  serverTimestamp: jest.fn(),
  updateDoc: jest.fn(),
  where: jest.fn(),
}));

import {
  buildCalendarPlanTasks,
  computePlannerAnalytics,
  parseDueDate,
} from "../../utils/plannerTaskSync";

describe("PlannerTaskSync", () => {
  test("parseDueDate handles Timestamp", () => {
    const timestamp = { toDate: () => new Date("2026-03-24T10:00:00Z") };
    expect(parseDueDate(timestamp)).toBeInstanceOf(Date);
  });

  test("parseDueDate handles Date", () => {
    const date = new Date("2026-03-24T10:00:00Z");
    expect(parseDueDate(date)).toBe(date);
  });

  test("parseDueDate handles string", () => {
    expect(parseDueDate("2026-03-24T10:00:00Z")).toBeInstanceOf(Date);
  });

  test("parseDueDate returns null for invalid", () => {
    expect(parseDueDate(null)).toBe(null);
    expect(parseDueDate("invalid")).toBe(null);
    expect(parseDueDate(undefined)).toBe(null);
  });

  test("computePlannerAnalytics day range", () => {
    const today = new Date("2026-03-23T12:00:00Z");
    const tasks = [
      { dueDate: new Date("2026-03-23T14:00:00Z") }, // today
      { dueDate: new Date("2026-03-24T10:00:00Z") }, // tomorrow
    ];
    const analytics = computePlannerAnalytics(tasks, today);
    expect(analytics.day.planned).toBe(1);
    expect(analytics.day.pending).toBe(1);
  });

  test("computePlannerAnalytics empty", () => {
    const today = new Date("2026-03-23T12:00:00Z");
    const analytics = computePlannerAnalytics([], today);
    expect(analytics.day.percent).toBe(0);
  });

  test("buildCalendarPlanTasks keeps only plans from the requested day", () => {
    const plans = [
      {
        id: "plan_today",
        dayKey: "2026-03-23",
        title: "Read chapter 4",
        note: "Physics",
        priority: "high",
        time: "2026-03-23T08:00:00.000Z",
      },
      {
        id: "plan_other",
        dayKey: "2026-03-24",
        title: "Draft report",
        note: "Research",
        priority: "medium",
        time: "2026-03-24T09:00:00.000Z",
      },
    ];

    const tasks = buildCalendarPlanTasks(
      new Date("2026-03-23T00:00:00.000Z"),
      "2026-03-23",
      plans
    );

    expect(tasks).toHaveLength(1);
    expect(tasks[0].plannerRef).toBe("calendar:day:2026-03-23:plan:plan_today");
    expect(tasks[0].title).toBe("Read chapter 4");
  });
});

import {
    calculateDailyWorkload,
    getWorkloadLabel,
} from "../../utils/workloadCalculator";

describe("Workload Calculator", () => {
  test("calculateDailyWorkload with no tasks returns 0", () => {
    expect(calculateDailyWorkload([])).toBe(0);
  });

  test("calculateDailyWorkload with completed tasks ignores them", () => {
    const tasks = [
      {
        type: "assignment",
        priority: "high",
        completed: true,
        dueAt: new Date(),
      },
    ];
    expect(calculateDailyWorkload(tasks)).toBe(0);
  });

  test("calculateDailyWorkload with past tasks ignores them", () => {
    const pastDate = new Date(Date.now() - 86400000);
    const tasks = [
      { type: "quiz", priority: "high", completed: false, dueAt: pastDate },
    ];
    expect(calculateDailyWorkload(tasks)).toBe(0);
  });

  test("calculateDailyWorkload with today task", () => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const tasks = [
      { type: "quiz", priority: "high", completed: false, dueAt: today },
    ];
    expect(calculateDailyWorkload(tasks)).toBe(8);
  });

  test("calculateDailyWorkload urgency weighting", () => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const tomorrow = new Date(today.getTime() + 86400000);
    const tasks = [
      {
        type: "assignment",
        priority: "medium",
        completed: false,
        dueAt: today,
      }, // 1 * 1.5 * 2 = 3
      {
        type: "assignment",
        priority: "medium",
        completed: false,
        dueAt: tomorrow,
      }, // 1 * 1.5 * 2 = 3
      {
        type: "assignment",
        priority: "medium",
        completed: false,
        dueAt: new Date(today.getTime() + 4 * 86400000),
      }, // 1 * 1.5 * 1.2 = 1.8
    ];
    expect(calculateDailyWorkload(tasks)).toBe(8);
  });

  test("getWorkloadLabel ranges", () => {
    expect(getWorkloadLabel(0)).toEqual({ label: "Light", color: "#22c55e" });
    expect(getWorkloadLabel(4)).toEqual({ label: "Light", color: "#22c55e" });
    expect(getWorkloadLabel(5)).toEqual({
      label: "Moderate",
      color: "#f59e0b",
    });
    expect(getWorkloadLabel(9)).toEqual({
      label: "Moderate",
      color: "#f59e0b",
    });
    expect(getWorkloadLabel(10)).toEqual({ label: "Heavy", color: "#ef4444" });
    expect(getWorkloadLabel(14)).toEqual({ label: "Heavy", color: "#ef4444" });
    expect(getWorkloadLabel(15)).toEqual({
      label: "Overwhelming",
      color: "#7c3aed",
    });
  });
});

